import{_ as n,o as e,c as i,a2 as l}from"./chunks/framework.DZrHScmQ.js";const b=JSON.parse('{"title":"Public and Private Context Boundary","description":"","frontmatter":{},"headers":[],"relativePath":"ai-native/context-system/public-private-boundary.md","filePath":"ai-native/context-system/public-private-boundary.md"}'),t={name:"ai-native/context-system/public-private-boundary.md"};function s(p,a,o,r,c,d){return e(),i("div",null,[...a[0]||(a[0]=[l(`<h1 id="public-and-private-context-boundary" tabindex="-1">Public and Private Context Boundary <a class="header-anchor" href="#public-and-private-context-boundary" aria-label="Permalink to &quot;Public and Private Context Boundary&quot;">​</a></h1><p><strong>状态：Draft</strong></p><h2 id="两个空间" tabindex="-1">两个空间 <a class="header-anchor" href="#两个空间" aria-label="Permalink to &quot;两个空间&quot;">​</a></h2><p>推荐把上下文基础设施拆成两个空间：</p><h3 id="public-handbook" tabindex="-1">Public Handbook <a class="header-anchor" href="#public-handbook" aria-label="Permalink to &quot;Public Handbook&quot;">​</a></h3><p>保存：</p><ul><li>通用原则和工作流</li><li>已脱敏的项目架构与契约</li><li>公共模板</li><li>可公开的案例和参考实现</li></ul><p>不保存：</p><ul><li>个人画像</li><li>未脱敏经营数据</li><li>原始工作日志</li><li>客户和账号信息</li><li>生产凭据与内部访问方式</li></ul><h3 id="private-context-workspace" tabindex="-1">Private Context Workspace <a class="header-anchor" href="#private-context-workspace" aria-label="Permalink to &quot;Private Context Workspace&quot;">​</a></h3><p>保存：</p><ul><li>用户和团队偏好</li><li>每日观察与反思</li><li>私密会议和经营上下文</li><li>内部事故证据</li><li>本地 Overlay、别名和路径</li></ul><p>私有 Workspace 可以引用 Handbook；Handbook 不反向依赖私密内容才能被理解。</p><h2 id="public-core-private-overlay" tabindex="-1">Public Core + Private Overlay <a class="header-anchor" href="#public-core-private-overlay" aria-label="Permalink to &quot;Public Core + Private Overlay&quot;">​</a></h2><p>工具和 Skill 也遵守同一结构：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Public Core</span></span>
<span class="line"><span>  - 通用 Contract</span></span>
<span class="line"><span>  - CLI / Schema</span></span>
<span class="line"><span>  - 测试</span></span>
<span class="line"><span>  - 文档</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Private Overlay</span></span>
<span class="line"><span>  - 账号和 Token</span></span>
<span class="line"><span>  - 联系人别名</span></span>
<span class="line"><span>  - 内部 Endpoint</span></span>
<span class="line"><span>  - 客户和业务默认值</span></span></code></pre></div><p>不要 Fork 一份公共 Skill 后把私密配置硬编码进去。优先通过环境变量、本地配置或薄 Bridge 叠加。</p><h2 id="晋升前脱敏" tabindex="-1">晋升前脱敏 <a class="header-anchor" href="#晋升前脱敏" aria-label="Permalink to &quot;晋升前脱敏&quot;">​</a></h2><p>从私有 Observation 晋升到公共 Handbook 前，检查：</p><ul><li>是否包含真实姓名、邮箱或客户名</li><li>是否包含内部 URL、项目 ID 或本地绝对路径</li><li>是否暴露密钥形态、账号或权限结构</li><li>案例是否可以抽象而不失去关键教训</li><li>原始证据是否应只保留内部链接</li></ul><p>无法脱敏的内容可以留在私有 L2，不必强行公开。</p>`,21)])])}const h=n(t,[["render",s]]);export{b as __pageData,h as default};
